```python
def check_permutation(str1, str2):
    # Angalia kama urefu wa nyuzi hizo mbili ni sawa
    if len(str1) != len(str2):
        return False

    # Hesabu idadi ya kila herufi katika kila nyuzi
    count1 = {}
    count2 = {}

    for char in str1:
        if char in count1:
            count1[char] += 1
        else:
            count1[char] = 1

    for char in str2:
        if char in count2:
            count2[char] += 1
        else:
            count2[char] = 1

    # Angalia kama idadi ya kila herufi ni sawa
    return count1 == count2
```

